const moment = require('moment-timezone');

const timezone = 'Asia/Riyadh';

// تحويل تاريخ UTC إلى توقيت السعودية
const toLocal = (date) => {
  if (!date) return null;
  return moment(date).tz(timezone).format('YYYY-MM-DD HH:mm:ss');
};

// الحصول على التاريخ والوقت الحالي بتوقيت السعودية
const now = () => {
  return moment().tz(timezone).format('YYYY-MM-DD HH:mm:ss');
};

// بداية اليوم بتوقيت السعودية (للفلترة)
const startOfDay = () => {
  return moment().tz(timezone).startOf('day').format('YYYY-MM-DD HH:mm:ss');
};

// نهاية اليوم
const endOfDay = () => {
  return moment().tz(timezone).endOf('day').format('YYYY-MM-DD HH:mm:ss');
};

module.exports = { toLocal, now, startOfDay, endOfDay };
